package com.xda.sa2ration.lut;
import java.util.ArrayList;import java.util.List;import java.util.Locale;
public final class CubeLut3D {public final String title;public final int size;public final double[][] values;private CubeLut3D(String title,int size,double[][]values){this.title=title;this.size=size;this.values=values;}public long estimatedBytes(){return (long)values.length*3*Double.BYTES;}public static CubeLut3D parse(String text){if(text==null)throw new IllegalArgumentException("Arquivo vazio");String title="Sem título";int size=0;List<double[]>values=new ArrayList<>();for(String raw:text.split("\\R")){String line=raw.trim();if(line.isEmpty()||line.startsWith("#"))continue;if(line.toUpperCase(Locale.US).startsWith("TITLE")){title=line.substring(5).trim().replace("\"","");continue;}if(line.toUpperCase(Locale.US).startsWith("LUT_3D_SIZE")){size=Integer.parseInt(line.substring(11).trim());if(size<2||size>128)throw new IllegalArgumentException("Tamanho LUT inválido");continue;}if(line.startsWith("DOMAIN_"))continue;String[]p=line.split("\\s+");if(p.length!=3)throw new IllegalArgumentException("Linha .cube inválida");double[]v={Double.parseDouble(p[0]),Double.parseDouble(p[1]),Double.parseDouble(p[2])};for(double n:v)if(!Double.isFinite(n))throw new IllegalArgumentException("LUT contém NaN/infinito");values.add(v);}long expected=(long)size*size*size;if(size==0||values.size()!=expected)throw new IllegalArgumentException("Esperados "+expected+" pontos, encontrados "+values.size());return new CubeLut3D(title,size,values.toArray(new double[0][]));}}
